import{_ as t,o,c as n,ag as a}from"./chunks/framework.BKDXG6j6.js";const p=JSON.parse('{"title":"Kotlin Coroutines","description":"","frontmatter":{},"headers":[],"relativePath":"foundation/kotlin/coroutines.md","filePath":"foundation/kotlin/coroutines.md","lastUpdated":1774424426000}'),s={name:"foundation/kotlin/coroutines.md"};function i(r,e,c,l,d,h){return o(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="kotlin-coroutines" tabindex="-1">Kotlin Coroutines <a class="header-anchor" href="#kotlin-coroutines" aria-label="Permalink to &quot;Kotlin Coroutines&quot;">​</a></h1><p>Coroutine là một concurrency design pattern để đơn giản hóa code xử lý bất đồng bộ (asynchronous).</p><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><h3 id="_1-what-is-a-coroutine" tabindex="-1">1. What is a Coroutine? <a class="header-anchor" href="#_1-what-is-a-coroutine" aria-label="Permalink to &quot;1. What is a Coroutine?&quot;">​</a></h3><p>Coroutines are &quot;lightweight threads&quot;. They don&#39;t map 1:1 to native OS threads. You can have thousands of coroutines running on a single thread. They achieve this via <strong>suspension</strong>—pausing execution without blocking the underlying thread.</p><h3 id="_2-suspend-functions" tabindex="-1">2. Suspend Functions <a class="header-anchor" href="#_2-suspend-functions" aria-label="Permalink to &quot;2. Suspend Functions&quot;">​</a></h3><p>Functions marked with the <code>suspend</code> keyword can pause and resume execution. They can only be called from a coroutine or another suspend function.</p><div class="language-kotlin vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">kotlin</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">suspend</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> fun</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> fetchUserData</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(): </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Network call</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_3-dispatchers" tabindex="-1">3. Dispatchers <a class="header-anchor" href="#_3-dispatchers" aria-label="Permalink to &quot;3. Dispatchers&quot;">​</a></h3><p>Determine which thread or thread pool the coroutine uses.</p><ul><li><strong><code>Dispatchers.Main</code></strong>: For UI operations.</li><li><strong><code>Dispatchers.IO</code></strong>: Disk or network I/O (database, API calls).</li><li><strong><code>Dispatchers.Default</code></strong>: CPU-intensive work (sorting lists, parsing JSON).</li><li><strong><code>Dispatchers.Unconfined</code></strong>: Starts in the caller thread, but resumes in whatever thread the suspending function used.</li></ul><h3 id="_4-coroutine-builders" tabindex="-1">4. Coroutine Builders <a class="header-anchor" href="#_4-coroutine-builders" aria-label="Permalink to &quot;4. Coroutine Builders&quot;">​</a></h3><p>Launch a new coroutine.</p><ul><li><strong><code>launch</code></strong>: Returns a <code>Job</code> and does not return any resulting value. Used for fire-and-forget tasks.</li><li><strong><code>async</code></strong>: Returns a <code>Deferred&lt;T&gt;</code> (a non-blocking future). Used to compute a result concurrently. You call <code>.await()</code> to get the result.</li></ul><h3 id="_5-coroutinescope-context" tabindex="-1">5. CoroutineScope &amp; Context <a class="header-anchor" href="#_5-coroutinescope-context" aria-label="Permalink to &quot;5. CoroutineScope &amp; Context&quot;">​</a></h3><p>Defines a lifecycle for coroutines. All coroutines must be launched in a scope.</p><ul><li>In Android, use architecture-aware scopes: <code>viewModelScope</code> (cancels when ViewModel clears) and <code>lifecycleScope</code> (cancels when Lifecycle destroys).</li><li><strong>Structured Concurrency</strong>: Ensures coroutines are not lost and leak memory. An outer scope waits for all its children to complete.</li></ul><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Inject Dispatchers:</strong> Avoid hardcoding <code>Dispatchers.IO</code>. Inject them for easier testing.</li><li><strong>Main-Safety:</strong> Suspend functions should be safe to call from the main thread. If a function does heavy lifting, it should internally switch contexts using <code>withContext(Dispatchers.IO)</code>.</li><li><strong>Cancellation:</strong> Check <code>isActive</code> in long-running loops. Coroutine cancellation is cooperative.</li></ol><h2 id="interview-questions" tabindex="-1">Interview Questions <a class="header-anchor" href="#interview-questions" aria-label="Permalink to &quot;Interview Questions&quot;">​</a></h2><p><strong>Q: What is the difference between <code>launch</code> and <code>async</code>?</strong><em>Answer:</em> <code>launch</code> is &quot;fire-and-forget&quot; and returns a <code>Job</code> (does not return a result). <code>async</code> performs a task that returns a result and returns a <code>Deferred&lt;T&gt;</code> object; you extract the result using <code>.await()</code>. Exceptions in <code>launch</code> crash the app (if not caught by an ExceptionHandler), while exceptions in <code>async</code> are encapsulated in the <code>Deferred</code> and thrown when <code>.await()</code> is called.</p><p><strong>Q: Explain what <code>withContext</code> does.</strong><em>Answer:</em> <code>withContext</code> is a suspend function that shifts the execution of a coroutine to a different Dispatcher. It suspends the caller until the block completes, making it ideal for returning results from background threads back to the main thread securely.</p>`,22)])])}const g=t(s,[["render",i]]);export{p as __pageData,g as default};
